      "keystrokes": "sleep 300; echo '=== LOG ==='; tail -60 /app/autotune.log; echo '=== PROC ==='; if [ -d /proc/2918 ]; then echo 'PID 2918 running'; else echo 'PID 2918 done'; fi; echo '=== FILES ==='; ls -lh /app/model*.bin 2>&1; echo '=== JOBS ==='; jobs\n",
      "duration": 60.0
